class Solution:
    def sortArray(self, nums):
        arr = list(nums)
        for i in range(len(arr)):
            m = i
            for j in range(i + 1, len(arr)):
                if arr[j] < arr[m]:
                    m = j
            arr[i], arr[m] = arr[m], arr[i]
        return arr

