class Solution:
    def sortArray(self, nums):
        def merge(a, b):
            out = []
            i = j = 0
            while i < len(a) and j < len(b):
                if a[i] <= b[j]:
                    out.append(a[i]); i += 1
                else:
                    out.append(b[j]); j += 1
            out.extend(a[i:])
            out.extend(b[j:])
            return out
        def sort(a):
            if len(a) <= 1:
                return a
            mid = len(a) // 2
            return merge(sort(a[:mid]), sort(a[mid:]))
        return sort(list(nums))

